const payload = $json.body ?? $json;
if (payload.entrada && payload.resultado && payload.decision) {
  return [{ json: payload }];
}
const context = payload.contexto ?? payload.context ?? {};
const memoria = payload.memoria ?? payload.memory ?? {};

function normalizeObject(value) {
  const normalized = String(value ?? '').trim().toLowerCase().replace(/[_\s]+/g, '_');
  const aliases = {
    pistol: 'arma',
    pistola: 'arma',
    handgun: 'arma',
    firearm: 'arma',
    weapon: 'arma',
    gun: 'arma',
    rifle: 'fusil',
    knife: 'arma_blanca',
    cuchillo: 'arma_blanca',
    scissors: 'arma_blanca',
    cellphone: 'cell_phone',
    mobile_phone: 'cell_phone',
    phone: 'cell_phone',
    nonviolence: 'no_violencia',
    non_violence: 'no_violencia',
    'non-violence': 'no_violencia',
    no_violence: 'no_violencia',
    'no-violence': 'no_violencia',
    normal: 'no_violencia',
    person: 'persona',
    people: 'multitud',
    crowd: 'multitud',
    pelea: 'violencia',
    fight: 'violencia',
    fighting: 'violencia',
    violence: 'violencia'
  };
  return aliases[normalized] ?? normalized;
}

function numberOrDefault(value, fallback = 0) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function reviewIdFor(camera, object, time) {
  return String(camera + '_' + object + '_' + time).replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 64) || 'sin_evento';
}

const objeto = normalizeObject(payload.objeto ?? payload.object);
const confianza = numberOrDefault(payload.confianza ?? payload.confidence);
const camara = String(payload.camara ?? payload.camera ?? payload.camara_id ?? 'PC-01');
const hora = String(payload.hora ?? payload.detected_at ?? new Date().toISOString());
const box = payload.box ?? null;
const imagen = payload.imagen ?? payload.image_path ?? payload.imagen_url ?? null;

const eventTime = new Date(hora);
const hour = Number.isNaN(eventTime.getTime()) ? new Date().getHours() : eventTime.getHours();
const isNight = hour >= 22 || hour <= 5;

return [
  {
    json: {
      agente: 'AgenteAnalisis',
      version: '0.4.0',
      entrada: { objeto, confianza, camara, hora, box, imagen },
      contexto: {
        zona: context.zona ?? context.zone ?? 'sin_zona',
        iluminacion: normalizeObject(context.iluminacion ?? context.lighting ?? 'desconocida'),
        cantidad_personas: numberOrDefault(context.cantidad_personas ?? context.people_count),
        hora_local: hour,
        noche: isNight
      },
      tracking: {},
      memoria: {
        eventos_previos_24h: numberOrDefault(memoria.eventos_previos_24h ?? memoria.previous_events_24h),
        alertas_previas_24h: numberOrDefault(memoria.alertas_previas_24h ?? memoria.previous_alerts_24h)
      },
      review_id: reviewIdFor(camara, objeto, hora)
    }
  }
];

const data = $json;
if (data.resultado && data.decision) {
  return [{ json: data }];
}
const objeto = data.entrada.objeto;
const confianza = data.entrada.confianza;
const contexto = data.contexto;
const memoria = data.memoria;

const objectBaseScores = {
  arma: 80,
  arma_blanca: 65,
  fusil: 95,
  violencia: 75,
  multitud: 35,
  persona_sospechosa: 45,
  no_violencia: 2,
  persona: 10,
  cell_phone: 5,
  car: 8,
  truck: 8,
  motorcycle: 10
};
const dangerousObjects = new Set(['arma', 'arma_blanca', 'fusil', 'violencia']);
let score = 0;
const factores = [];

function add(points, code, detail) {
  score += points;
  factores.push({ code, points, detail });
}

if (!objeto) {
  add(5, 'payload_incompleto', 'No se recibio objeto detectable.');
} else if (Object.prototype.hasOwnProperty.call(objectBaseScores, objeto)) {
  const code = dangerousObjects.has(objeto) ? 'objeto_peligroso' : 'objeto_base';
  add(objectBaseScores[objeto], code, 'Objeto detectado: ' + objeto + '.');
} else {
  add(8, 'objeto_observado', 'Objeto observado sin regla critica: ' + objeto + '.');
}

if (objeto === 'persona' && contexto.cantidad_personas >= 2) {
  add(5, 'multiples_personas', 'Personas detectadas en escena: ' + contexto.cantidad_personas + '.');
}

if (confianza >= 0.9) add(10, 'alta_confianza', 'Confianza alta: ' + confianza + '.');
else if (confianza >= 0.7) add(5, 'confianza_media', 'Confianza aceptable: ' + confianza + '.');
else add(-10, 'baja_confianza', 'Confianza baja: ' + confianza + '.');

if (contexto.noche) add(15, 'horario_nocturno', 'Evento detectado en horario nocturno.');
if (['baja', 'oscura', 'low', 'dark'].includes(contexto.iluminacion)) add(10, 'baja_iluminacion', 'Condicion de baja iluminacion.');
if (memoria.alertas_previas_24h >= 2) add(15, 'historial_alertas', 'La camara/zona tiene alertas recientes.');
if (memoria.eventos_previos_24h >= 10) add(8, 'historial_eventos', 'La camara/zona tiene actividad reciente alta.');

score = Math.max(0, Math.min(100, Math.round(score)));
let riesgo = 'BAJO';
let severidad = 'INFORMATIVA';
if (score >= 90) {
  riesgo = 'CRITICO';
  severidad = 'CRITICA';
} else if (score >= 70) {
  riesgo = 'ALTO';
  severidad = 'ALTA';
} else if (score >= 30) {
  riesgo = 'MEDIO';
  severidad = 'MEDIA';
}

return [
  {
    json: {
      ...data,
      resultado: {
        riesgo,
        nivel_riesgo: riesgo,
        severidad,
        score,
        score_riesgo: Math.round((score / 100) * 10000) / 10000,
        factores,
        algoritmo: 'risk_rules_v5_seguridad_multiclase'
      }
    }
  }
];

const data = $json;
if (data.persistencia && data.resultado && data.decision) {
  return [{ json: data }];
}
const score = data.resultado.score;
const riesgo = data.resultado.riesgo;
const reviewId = data.review_id ?? data.persistencia?.review_id ?? 'sin_evento';

let accion = 'REGISTRAR_EVENTO';
let prioridad = 2;
let notificar = false;
const canales = [];
const accionesHumanas = ['CONFIRMAR_AMENAZA', 'FALSO_POSITIVO', 'REQUIERE_MAS_REVISION'];
let requiereRevisionHumana = false;
let estadoRevisionHumana = 'NO_REQUERIDA';
let automatizacionBloqueada = false;

if (score >= 90) {
  accion = 'SOLICITAR_VALIDACION_URGENTE';
  prioridad = 10;
  notificar = true;
  canales.push('telegram_supervisor', 'dashboard_realtime');
  requiereRevisionHumana = true;
  estadoRevisionHumana = 'PENDIENTE';
  automatizacionBloqueada = true;
} else if (score >= 70) {
  accion = 'SOLICITAR_VALIDACION_HUMANA';
  prioridad = 8;
  notificar = true;
  canales.push('telegram_supervisor', 'dashboard_realtime');
  requiereRevisionHumana = true;
  estadoRevisionHumana = 'PENDIENTE';
  automatizacionBloqueada = true;
} else if (score >= 30) {
  accion = 'SOLICITAR_REVISION_HUMANA';
  prioridad = 5;
  notificar = true;
  canales.push('telegram_supervisor');
  requiereRevisionHumana = true;
  estadoRevisionHumana = 'PENDIENTE';
  automatizacionBloqueada = true;
} else if (data.entrada.confianza < 0.5) {
  accion = 'IGNORAR_BAJA_CONFIANZA';
  prioridad = 1;
}

return [
  {
    json: {
      status: 'procesado',
      pipeline: ['AgentePercepcion', 'AgenteAnalisis', 'AgenteRiesgo', 'AgenteAccion', 'AgenteMemoria', 'AgenteInterfazHumana'],
      agente: data.agente,
      version: data.version,
      entrada: data.entrada,
      contexto: data.contexto,
      tracking: {},
      memoria: data.memoria,
      resultado: data.resultado,
      decision: {
        accion,
        accion_tomada: accion,
        prioridad,
        notificar,
        canales,
        guardar_en_supabase: true,
        requiere_revision_humana: requiereRevisionHumana,
        estado_revision_humana: estadoRevisionHumana,
        acciones_humanas_permitidas: requiereRevisionHumana ? accionesHumanas : [],
        automatizacion_bloqueada: automatizacionBloqueada,
        review_id: reviewId
      },
      persistencia: {
        camara_id: data.entrada.camara,
        objeto: data.entrada.objeto,
        confianza: data.entrada.confianza,
        score_riesgo: data.resultado.score_riesgo,
        nivel_riesgo: data.resultado.nivel_riesgo,
        accion_tomada: accion,
        alertas_previas_24h: data.memoria.alertas_previas_24h,
        detected_at: data.entrada.hora,
        box: data.entrada.box,
        contexto: data.contexto,
        tracking: {},
        memoria: data.memoria,
        requiere_revision_humana: requiereRevisionHumana,
        estado_revision_humana: estadoRevisionHumana,
        review_id: reviewId
      },
      mensaje: accion + ': ' + riesgo + ' con score ' + data.resultado.score_riesgo,
      siguientes_agentes: {
        interfaz_humana: requiereRevisionHumana ? 'telegram_supervisor_pendiente' : 'no_requerida',
        prediccion_ml: 'pendiente_fase_siguiente',
        dashboard: 'listo_para_realtime'
      },
      procesado_en: new Date().toISOString()
    }
  }
];

const data = $json;
const risk = data.resultado?.nivel_riesgo ?? "BAJO";
const event = data.entrada ?? {};
const tracking = data.tracking ?? {};
const decision = data.decision ?? {};
const score = data.resultado?.score_riesgo ?? 0;
const reviewRequired = Boolean(
  decision.requiere_revision_humana ?? decision.requires_human_review,
);
const reviewStatus = decision.estado_revision_humana ?? decision.human_review_status ?? "NO_REQUERIDA";
const reviewId = data.persistencia?.review_id ?? decision.review_id ?? data.review_id ?? "";
const legacyTrackId = tracking.track_id ?? tracking.person_id ?? "";
const reviewKey = sanitizeKey(reviewId || legacyTrackId || `${event.camara ?? "PC-01"}_${event.objeto ?? "unknown"}_${event.hora ?? Date.now()}`);
const factors = (data.resultado?.factores ?? [])
  .slice(-5)
  .map((factor) => `- ${escapeHtml(factor.code)}: ${escapeHtml(factor.detail)}`)
  .join("\n");

function sanitizeKey(value) {
  const safe = String(value).replace(/[^a-zA-Z0-9_-]/g, "").slice(0, 40);
  return safe || "sin_evento";
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

const text = [
  `<b>SentinelAI - Revision ${escapeHtml(risk)}</b>`,
  `Accion: ${escapeHtml(decision.accion_tomada ?? decision.accion ?? "REGISTRAR_EVENTO")}`,
  `Revision humana: ${escapeHtml(reviewStatus)}`,
  `Camara: ${escapeHtml(event.camara ?? "PC-01")}`,
  `Objeto: ${escapeHtml(event.objeto ?? "unknown")} (${escapeHtml(event.confianza ?? 0)})`,
  `Score: ${escapeHtml(score)}`,
  data.resultado?.resumen_ia ? `IA: ${escapeHtml(data.resultado.resumen_ia)}` : null,
  factors ? `Factores:\n${factors}` : null,
].filter(Boolean).join("\n");

return [
  {
    json: {
      text,
      parse_mode: "HTML",
      disable_notification: !["CRITICO", "ALTO"].includes(risk),
      reply_markup: reviewRequired
        ? {
            inline_keyboard: [
              [
                { text: "Confirmar amenaza", callback_data: `sentinel:confirm:${reviewKey}` },
                { text: "Falso positivo", callback_data: `sentinel:false:${reviewKey}` },
              ],
              [
                { text: "Mas revision", callback_data: `sentinel:review:${reviewKey}` },
              ],
            ],
          }
        : undefined,
      review_context: {
        review_id: reviewKey,
        tracking_id: legacyTrackId || null,
        camara_id: event.camara ?? "PC-01",
        objeto: event.objeto ?? "unknown",
        requires_human_review: reviewRequired,
        human_review_status: reviewStatus,
        risk,
        score,
      },
    },
  },
];

const payload = $json.body ?? $json;
const callback = payload.callback_query ?? payload.callback ?? {};
const callbackData = String(callback.data ?? payload.callback_data ?? "");
const parts = callbackData.split(":");

const actionMap = {
  confirm: {
    human_label: "real_threat",
    estado_revision_humana: "CONFIRMADA",
    accion_final: "ACTIVAR_PROTOCOLO",
    alimentar_entrenamiento: true,
  },
  false: {
    human_label: "false_positive",
    estado_revision_humana: "FALSO_POSITIVO",
    accion_final: "CERRAR_EVENTO",
    alimentar_entrenamiento: true,
  },
  review: {
    human_label: "needs_more_review",
    estado_revision_humana: "REQUIERE_MAS_REVISION",
    accion_final: "SOLICITAR_MAS_CONTEXTO",
    alimentar_entrenamiento: false,
  },
};

const actionKey = parts[0] === "sentinel" ? parts[1] ?? "" : "";
const reviewId = parts[0] === "sentinel" ? parts[2] ?? "" : payload.review_id ?? "";
const trackingId = payload.tracking_id ?? "";
const selected = actionMap[actionKey] ?? {
  human_label: "unknown",
  estado_revision_humana: "DESCONOCIDA",
  accion_final: "REVISAR_MANUALMENTE",
  alimentar_entrenamiento: false,
};

return [
  {
    json: {
      source: "telegram_supervisor",
      callback_data: callbackData,
      review_id: reviewId,
      tracking_id: trackingId,
      answer_callback_query: {
        callback_query_id: callback.id ?? payload.callback_query_id ?? null,
        text: `SentinelAI: ${selected.estado_revision_humana}`,
        show_alert: false,
      },
      supervisor: {
        user_id: callback.from?.id ?? payload.user_id ?? null,
        username: callback.from?.username ?? payload.username ?? null,
        decided_at: new Date().toISOString(),
        ...selected,
      },
      persistencia_feedback: {
        review_id: reviewId,
        tracking_id: trackingId,
        camara_id: payload.camara_id ?? null,
        detection_event_id: payload.detection_event_id ?? null,
        human_label: selected.human_label,
        estado_revision_humana: selected.estado_revision_humana,
        accion_final: selected.accion_final,
        supervisor_user_id: callback.from?.id ?? payload.user_id ?? null,
        supervisor_username: callback.from?.username ?? payload.username ?? null,
        alimentar_entrenamiento: selected.alimentar_entrenamiento,
        raw_callback: callbackData,
        decided_at: new Date().toISOString(),
      },
    },
  },
];
